function active$CashFlowArticles(f) {onChange$Kind(f); f.add_onResponseComplete(on$CashFlowArticles$ResponseComplete);}
function close$CashFlowArticles(f) {try {f.remove_onResponseComplete(on$CashFlowArticles$ResponseComplete)} catch (ex) {}}
function on$CashFlowArticles$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_ct');
      break;
    default:
      break;
  }
}
function onChange$Item(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'kind':
      onChange$Kind(f, true);
      break;
    default:
      break;
  }
}
function onChange$Kind(f, force) {window.setTimeout(String.format('onFocus$Kind(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$Kind(id, force) {
  var f = $find(id), k = (f.getItemValue('kind') == 2 || f.getItemValue('kind') == 3);
  setItemDisable(f, 'ds_tk_du, ds_tk_gt, ds_ma_loai, ds_ma_phi', k);
  setFieldsEmpty(f, 'ds_tk_du, ds_tk_gt, ds_ma_loai, ds_ma_phi', !k);
}
function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
function setFieldsEmpty(f, c, v){
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if(!v) o.value = '';
  }
}

      &ScriptIrregular;
